# Wrapper for COMMAND_NAME - runs security scanner before run/start commands.
# Generated by install.sh. REAL_BINARY and SCANNER_DIR are replaced at install.
REAL_BINARY="REAL_BINARY_PLACEHOLDER"
SCANNER_DIR="SCANNER_DIR_PLACEHOLDER"

# Use real node to run the wrapper (so we don't depend on PATH order for node)
exec "$REAL_BINARY" "$SCANNER_DIR/run-wrapper.js" "COMMAND_NAME_PLACEHOLDER" "$@"
